#!/usr/bin/env bash
set -u

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
FAILED=0

fail() {
  printf 'FAIL: %s\n' "$1" >&2
  FAILED=1
}

pass() {
  printf 'PASS: %s\n' "$1"
}

require_file() {
  local file="$1"
  if [ -f "$ROOT_DIR/$file" ]; then
    pass "file exists: $file"
  else
    fail "missing file: $file"
  fi
}

require_exec() {
  local file="$1"
  if [ -x "$ROOT_DIR/$file" ]; then
    pass "executable: $file"
  else
    fail "not executable: $file"
  fi
}

require_text() {
  local file="$1"
  local pattern="$2"
  local label="$3"
  if grep -Eq -- "$pattern" "$ROOT_DIR/$file"; then
    pass "$label"
  else
    fail "$label"
  fi
}

forbid_text() {
  local file="$1"
  local pattern="$2"
  local label="$3"
  if grep -Eq -- "$pattern" "$ROOT_DIR/$file"; then
    fail "$label"
  else
    pass "$label"
  fi
}

require_same_assignment() {
  local file_a="$1"
  local file_b="$2"
  local name="$3"
  local label="$4"
  local value_a
  local value_b
  value_a="$(sed -n "s/^${name}=//p" "$ROOT_DIR/$file_a")"
  value_b="$(sed -n "s/^${name}=//p" "$ROOT_DIR/$file_b")"
  if [ -n "$value_a" ] && [ "$value_a" = "$value_b" ]; then
    pass "$label"
  else
    fail "$label"
  fi
}

