if python3 - "$ROOT_DIR" <<'PY'
import importlib.util
import pathlib
import sys
from html.parser import HTMLParser

root = pathlib.Path(sys.argv[1])
spec = importlib.util.spec_from_file_location("agentparty_lint_contract", root / "scripts/agentparty.py")
module = importlib.util.module_from_spec(spec)
assert spec.loader is not None
spec.loader.exec_module(module)


class CommandCardParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.command_cards = 0
        self.command_card_depth = 0
        self.copy_commands = []

    def handle_starttag(self, tag, attrs):
        attr = {key: value or "" for key, value in attrs}
        starts_card = tag == "article" and "command-card" in attr.get("class", "").split()
        if starts_card:
            self.command_cards += 1
            self.command_card_depth = 1
        elif self.command_card_depth:
            self.command_card_depth += 1
        if tag == "button" and self.command_card_depth and attr.get("data-copy"):
            self.copy_commands.append(attr["data-copy"])

    def handle_endtag(self, tag):
        if self.command_card_depth:
            self.command_card_depth -= 1


parser = CommandCardParser()
parser.feed((root / "web/index.html").read_text(encoding="utf-8"))
errors = []
if parser.command_cards != module.EXPECTED_WEB_COMMAND_CARDS:
    errors.append(f"expected {module.EXPECTED_WEB_COMMAND_CARDS} command cards, found {parser.command_cards}")
if parser.copy_commands != module.EXPECTED_WEB_COPY_COMMANDS:
    missing = [command for command in module.EXPECTED_WEB_COPY_COMMANDS if command not in parser.copy_commands]
    unexpected = [command for command in parser.copy_commands if command not in module.EXPECTED_WEB_COPY_COMMANDS]
    if missing:
        errors.append("missing command cards: " + " | ".join(missing))
    if unexpected:
        errors.append("unexpected command cards: " + " | ".join(unexpected))
    if not missing and not unexpected:
        errors.append("command cards match as a set but are out of order")
if errors:
    for error in errors:
        print(error, file=sys.stderr)
    raise SystemExit(1)
PY
then
  pass "website command-card copy commands match AgentParty release-check contract"
else
  fail "website command-card copy commands match AgentParty release-check contract"
fi
